// MARK: - Promo Service

class PromoService {
    static let shared = PromoService()
    
    private var appliedPromoCodes: [String] = []
    private let userDefaults = UserDefaults.standard
    private let appliedPromoCodesKey = "appliedPromoCodes"
    
    private init() {
        appliedPromoCodes = userDefaults.stringArray(forKey: appliedPromoCodesKey) ?? []
    }
    
    func validateAndApplyPromo(code: String, discount: Int, completion: @escaping (PromoApplicationResult) -> Void) {
        // Check if promo code is empty
        guard !code.isEmpty else {
            completion(PromoApplicationResult(
                success: false,
                message: "Invalid promo code. The code cannot be empty.",
                appliedDiscount: nil,
                promoCode: nil
            ))
            return
        }
        
        // Check if discount is within valid range
        guard discount > 0 && discount <= 100 else {
            completion(PromoApplicationResult(
                success: false,
                message: "Invalid discount percentage. Must be between 1 and 100.",
                appliedDiscount: nil,
                promoCode: code
            ))
            return
        }
        
        // Check if already applied
        guard !appliedPromoCodes.contains(code.uppercased()) else {
            completion(PromoApplicationResult(
                success: false,
                message: "Promo code '\(code)' has already been applied to your account.",
                appliedDiscount: nil,
                promoCode: code
            ))
            return
        }
        
        // Simulate server-side validation
        validateWithServer(code: code, discount: discount) { [weak self] isValid in
            guard let self = self else { return }
            
            if isValid {
                self.applyToAccount(code: code.uppercased(), discount: discount)
                completion(PromoApplicationResult(
                    success: true,
                    message: "🎉 Promo code '\(code)' applied successfully! You received a \(discount)% discount.",
                    appliedDiscount: discount,
                    promoCode: code
                ))
            } else {
                completion(PromoApplicationResult(
                    success: false,
                    message: "Promo code '\(code)' is invalid or has expired.",
                    appliedDiscount: nil,
                    promoCode: code
                ))
            }
        }
    }
    
    private func validateWithServer(code: String, discount: Int, completion: @escaping (Bool) -> Void) {
        // Simulate network delay for server validation
        DispatchQueue.global().asyncAfter(deadline: .now() + 1.0) {
            // In production, make an actual API call here
            // For demo purposes, accept all codes that are at least 3 characters
            let isValid = code.count >= 3
            DispatchQueue.main.async {
                completion(isValid)
            }
        }
    }
    
    private func applyToAccount(code: String, discount: Int) {
        appliedPromoCodes.append(code)
        userDefaults.set(appliedPromoCodes, forKey: appliedPromoCodesKey)
        
        // Store the current active discount
        userDefaults.set(discount, forKey: "activeDiscount")
        userDefaults.set(code, forKey: "activePromoCode")
        userDefaults.synchronize()
        
        NotificationCenter.default.post(
            name: .promoCodeApplied,
            object: nil,
            userInfo: ["code": code, "discount": discount]
        )
    }
    
    func getAppliedPromoCodes() -> [String] {
        return appliedPromoCodes
    }
    
    func getActiveDiscount() -> Int? {
        let discount = userDefaults.integer(forKey: "activeDiscount")
        return discount > 0 ? discount : nil
    }
    
    func getActivePromoCode() -> String? {
        return userDefaults.string(forKey: "activePromoCode")
    }
    
    func clearAllPromos() {
        appliedPromoCodes.removeAll()
        userDefaults.removeObject(forKey: appliedPromoCodesKey)
        userDefaults.removeObject(forKey: "activeDiscount")
        userDefaults.removeObject(forKey: "activePromoCode")
        userDefaults.synchronize()
    }
}

