// MARK: - Universal Link Handler

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private let validHost = "myapp.com"
    private let promoPath = "/promo"
    
    private init() {}
    
    struct PromoLinkParameters {
        let code: String
        let discount: Int
    }
    
    func handleUniversalLink(url: URL) -> PromoLinkParameters? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            print("❌ Failed to parse URL components from: \(url)")
            return nil
        }
        
        // Validate host
        guard components.host == validHost else {
            print("❌ Invalid host: \(components.host ?? "nil"). Expected: \(validHost)")
            return nil
        }
        
        // Validate path
        guard components.path == promoPath else {
            print("❌ Invalid path: \(components.path). Expected: \(promoPath)")
            return nil
        }
        
        // Extract query parameters
        guard let queryItems = components.queryItems else {
            print("❌ No query parameters found in URL")
            return nil
        }
        
        var code: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name.lowercased() {
            case "code":
                code = item.value?.trimmingCharacters(in: .whitespacesAndNewlines)
            case "discount":
                if let value = item.value, let discountValue = Int(value) {
                    discount = discountValue
                }
            default:
                print("ℹ️ Ignoring unknown parameter: \(item.name)")
            }
        }
        
        guard let promoCode = code, !promoCode.isEmpty else {
            print("❌ Missing or empty 'code' parameter")
            return nil
        }
        
        guard let discountPercentage = discount else {
            print("❌ Missing or invalid 'discount' parameter")
            return nil
        }
        
        print("✅ Extracted promo parameters - Code: \(promoCode), Discount: \(discountPercentage)%")
        return PromoLinkParameters(code: promoCode, discount: discountPercentage)
    }
}

